/**
 * Role-based Experience Fragment — Early swap and Foundation re-init.
 *
 * Two-phase approach:
 * 1. Early swap (performEarlySwap function) — runs synchronously when this file is parsed
 *    within the bundled all.js. Reads localStorage role and clones matching <template>
 *    into .xf-role-default. Sets data-xf-swapped on wrapper when a swap occurs.
 *    No flicker observed because all.js loads early in page lifecycle (pre-paint).
 *    NOTE: Originally inline in HTML to prevent flicker when used in header; now safe to
 *    externalize since header no longer uses role-based XF switching.
 * 2. DOMContentLoaded handler — runs after jQuery available and handles:
 *    - Foundation plugin re-initialization on newly inserted nodes
 *    - Mega-menu hoverIntent rebinding (header.js bound to original DOM nodes)
 */
(function () {
    'use strict';

    // EARLY SWAP — runs synchronously when this file is parsed
    // Replaces inline <script> that was previously in experiencefragmentrole.html component.
    // NOTE: Timing depends on when clientlib JS loads relative to browser paint.
    function performEarlySwap() {
        var wrappers = document.querySelectorAll('.xf-role-wrapper');
        var userRole;
        try { userRole = localStorage.getItem('cibcpublic.userRole'); } catch (e) {}

        if (userRole && wrappers.length) {
            Array.prototype.forEach.call(wrappers, function (wrapper) {
                var matchedTemplate = null;
                Array.prototype.forEach.call(
                    wrapper.querySelectorAll('template[data-role]'),
                    function (t) {
                        if (t.getAttribute('data-role') === userRole) {
                            matchedTemplate = t;
                        }
                    }
                );
                if (matchedTemplate) {
                    var defaultContent = wrapper.querySelector('.xf-role-default');
                    if (defaultContent) {
                        var clone = document.importNode(matchedTemplate.content, true);
                        defaultContent.innerHTML = '';
                        defaultContent.appendChild(clone);
                        wrapper.setAttribute('data-xf-swapped', userRole);
                    }
                }
            });
        }
    }

    performEarlySwap();

    document.addEventListener('DOMContentLoaded', function () {
        if (window.Granite && window.Granite.author) {
            return;
        }

        var wrappers = document.querySelectorAll('.xf-role-wrapper');
        if (!wrappers.length) {
            return;
        }

        Array.prototype.forEach.call(wrappers, function (wrapper) {
            var wasSwapped = wrapper.hasAttribute('data-xf-swapped');

            // Investor / no role — inline script did not swap. Reflow Foundation
            // for interchange (banner images) and equalizer only.
            if (!wasSwapped) {
                if (window.$ && typeof $.fn.foundation === 'function') {
                    $(document).foundation('interchange', 'reflow');
                    $(document).foundation('equalizer', 'reflow');
                }
                return;
            }

            // Inline script swapped content. Re-initialize Foundation on the new nodes
            // (off-canvas for mobile hamburger, interchange for banner images, equalizer).
            // Use 'reflow' instead of a full init to avoid double event binding on
            // plugins (off-canvas, accordion) that were already initialised on page load.
            if (window.$ && typeof $.fn.foundation === 'function') {
                $(document).foundation('reflow');
                $(document).foundation('interchange', 'reflow');
                $(document).foundation('equalizer', 'reflow');
            }

            // Rebind mega-menu hoverIntent. header.js bound directly to DOM nodes at
            // DOMContentLoaded; those nodes were replaced by the inline swap.
            if (window.$ && $.fn.hoverIntent) {
                var items = $(wrapper).find('.top-bar-section-c .super-category > li > a');
                if (items.length) {
                    items.parent('li').hoverIntent({
                        over: function () {
                            $(this).addClass('hover');
                            $(this).children('.dropdown-aem').attr('aria-hidden', 'false');
                            if ($(this).hasClass('has-dropdown')) {
                                $(this).children('a').attr('aria-expanded', 'true');
                            }
                        },
                        out: function () {
                            $(this).removeClass('hover');
                            $(this).children('.dropdown-aem').attr('aria-hidden', 'true');
                            if ($(this).hasClass('has-dropdown')) {
                                $(this).children('a').attr('aria-expanded', 'false');
                            }
                            $(this).children('a').blur();
                        },
                        timeout: 50
                    });
                }
            }
        });
    });
}());

function checkOptanonCookie(cookieId) {
	var optanonCookie = $.cookie('OptanonConsent');
	if (optanonCookie) {
		var groupsIndex = optanonCookie.indexOf('groups=');
		if (groupsIndex !== -1) {
			var cookieGroups = optanonCookie.slice(groupsIndex).split('&')[0].split('=')[1]; 
			var groupsArray = cookieGroups.split(',');
			for (var i = 0; i < groupsArray.length; i++) {
				var group = groupsArray[i].split(':');
				if (group[0] === cookieId) {
					return parseInt(group[1]);
				}
			}
		}
	}
	return null;
}

function isOneTrustEnabled() {
    // satellite container property id
    const oneTrustGroups = _satellite?._container?.dataElements?.OnetrustActiveGroups;
    // check if either OneTrust or satellite container property Id exist to determine if onetrust is enabled
	if (typeof OneTrust !== "undefined" || oneTrustGroups !== undefined) {
		return true;
	}else{
		return false;
	}
}

function callOTbannerClick(event){
	event.preventDefault();
	OneTrust.ToggleInfoDisplay();
	setupOneTrustClickHandler(document.activeElement);
}

function setupOneTrustClickHandler($clickedElement) {
	$('body').on('click', function (event) {
		var target = $(event.target);
		var buttonClicked = (
			target.is('#accept-recommended-btn-handler') ||
			target.is('.onetrust-close-btn-handler')
		);
		var clsButtonClicked = target.is('#close-pc-btn-handler');

		if (buttonClicked ) {
			setTimeout(function () {
				document.location.reload();
			}, 1000);
		}
		if (clsButtonClicked) {
			$('.youtube-notification button').each(function(){
				$(this).attr('aria-expanded', 'false');
			});
			$('.pseudo-login-notification-content button').each(function(){
				$(this).attr('aria-expanded', 'false');
			});
		}
		$clickedElement.focus();
	});
}
﻿(function (){
    "use strict"
    var $ = window.jQuery;
    var CookieDate = new Date;
    CookieDate.setFullYear(CookieDate.getFullYear() +5);

    //cibc / US / investorsedge header click
    $( ".nav-primary .secondary-links .language .language-switcher" ).on( "click", function() {
        var position = 'header';
        updateAnalyticsLangSwitcher(position);
    });

    //cibc / US / investorsedge footer click
    $( "footer .lower-links .language-switcher" ).on( "click", function() {
        var position = 'footer';
        updateAnalyticsLangSwitcher(position);
    });

     //if user did choose the French/English language SAVE it in cookie
     //cibc en/fr and US en
     $( "#langSwitcher .languageswitcherlist .languages a" ).on( "click", function() {
        	//only for cibc.com
            if ( $(this).attr('data-localepath').indexOf('/fr/') !== -1 || $( this ).attr('lang') == "fr" ) {
                var lang = 'fr_CA';
                Cookies.set('langselected', lang, { expires: CookieDate });
                updateAnalyticsSelectLanguage(lang);
            } else if ( $(this).attr('data-localepath').indexOf('/en/') !== -1 || $( this ).attr('lang') == "en") {
                if ( $(this).attr('data-localepath').indexOf('/uspublic/') !== -1 || $( this ).attr('href').indexOf('/us.cibc.com/') !== -1 ) {     //US
                    var lang = 'en_US';                    
                    updateAnalyticsSelectLanguage(lang);
                } else {
                    var lang = 'en_CA';
                    Cookies.set('langselected', lang, { expires: CookieDate });
                    updateAnalyticsSelectLanguage(lang);
                }
            } 
    });
     
    //cibc other languages
    $( "#langSwitcher .languageswitcherlist .other-langs ul.o-langs a" ).on( "click", function() {
        var lang = '';
        if ( $( this ).attr('lang') == "zh-Hans" ) { 
            lang = 'zh_CA';
        } else if ( $( this ).attr('lang') == "zh-Hant" ) {
            lang = 'zt_CA';
        } else if ( $( this ).attr('lang') == "ar" ) {
            lang = 'ar_CA';
        } else if ( $( this ).attr('lang') == "ko" ) {
            lang = 'ko_CA';
        } else if ( $( this ).attr('lang') == "pa" ) {
            lang = 'pa_CA';
        }
        updateAnalyticsSelectLanguage(lang);
    });

    function updateAnalyticsLangSwitcher(position) {
        window.digitalData.interaction = window.digitalData.interaction || {};
        window.digitalData.events.pageView=false;
        window.digitalData.events.siteInteraction=true;
        if(typeof window.digitalData.events.advertisingImpression !=="undefined")
        	window.digitalData.events.advertisingImpression = false;
        window.digitalData.interaction.name="languageselector:open:" + position;
        if(typeof _satellite!=="undefined")_satellite.track("track");
    }

    function updateAnalyticsSelectLanguage(lang) {
        window.digitalData.interaction = window.digitalData.interaction || {};   
        window.digitalData.events.pageView=false; 
        window.digitalData.events.siteInteraction=true;
        if(typeof window.digitalData.events.advertisingImpression !=="undefined")
        	window.digitalData.events.advertisingImpression = false;
        window.digitalData.interaction.name="languageselector:click:" + lang;
        if(typeof _satellite!=="undefined")_satellite.track("track");
   
    }
    //investorsedge language selection
    $( "#langSwitcher .inner-wrapper a.button" ).on( "click", function() {
        if (  $( this ).attr('href').indexOf("/fr/") === -1 ) {
            var lang = 'en_CA';
            updateAnalyticsSelectLanguage(lang);
        } else {
            var lang = 'fr_CA';
            updateAnalyticsSelectLanguage(lang);
        }
    });

    $('#mobile-header .language-switcher').on('click', function() {
        $('#mobile-header li.has-submenu').removeClass('open');
    });
}());
