/*
 * This file is used for updating analytics data layer
 */
(function () {
	$(function() {
		var analyticsPrevData="";
		$(".tabsContainer .tabsNavigator .tabs-anchor").on('click', function(e) {
			var content = $(this).find(".tabText,.tile-text").contents().filter(function() {
				// need to check for text node type because filter excludes them when filtering by css selector
				return (this.nodeType === 3) || (!$(this).hasClass('show-for-sr'));
			});
			var tabLabelOverride = $(this).find(".tab-label-override").text();
			var anayticsData = (tabLabelOverride != undefined && tabLabelOverride.length > 0 )? tabLabelOverride.trim() : content.text().trim();
			if( analyticsPrevData != anayticsData ) {
				updateDataLayer("tab",anayticsData );
				analyticsPrevData = anayticsData;
			}
		});
		
		$(".accordionContainer .accordion .accordion-navigation .accordionTitle").on('click', function(e) {
			var content = $(this).find(".tabText").contents().filter(function() {
				return (this.nodeType === 3) || (!$(this).hasClass('show-for-sr'));
			});
			var accordionLabelOverride = $(this).find(".accordion-label-override").text();
			var anayticsData = (accordionLabelOverride != undefined  && accordionLabelOverride.length > 0 )? accordionLabelOverride.trim() : content.text().trim();
			if( analyticsPrevData != anayticsData ){
				updateDataLayer("accordion",anayticsData );
				analyticsPrevData = anayticsData;
			}
			});
		$(".tab-dropdown-style-container .tab-dropdown-style-wrapper .tab-dropdown-style-list > li").on('click', function(e) {
			var content = $(this).contents().filter(function() {
				// need to check for text node type because filter excludes them when filtering by css selector
				return (this.nodeType === 3) || (!$(this).hasClass('show-for-sr'));
			});
			var tabLabelOverride = $(this).find(".tab-label-override").text();
			var anayticsData = (tabLabelOverride != undefined && tabLabelOverride.length > 0 )? tabLabelOverride.trim() : content.text().trim();
			if( analyticsPrevData != anayticsData ) {
				updateDataLayer("tab",anayticsData );
				analyticsPrevData = anayticsData;
			}
		});

		$(".stickynav .sticky-nav .sticky-nav-items ul li .stickyAnchorTab .stickyAnchorText a").on('click', function(e) {
			var content = $(this).contents();
			updateDataLayer("stickynav",content.text().trim());
		});
    	
	function updateDataLayer(type,tabname){
		var interactionName = replaceSpaceWithHphen(window.digitalData.site.name) + ":"+ replaceCommaWithHphen(window.digitalData.page.hierarchy) + ":" + 
		replaceSpaceWithHphen(window.digitalData.page.name) + ":"+ type + ":" + replaceSpaceWithHphen(tabname);
		window.digitalData.interaction = window.digitalData.interaction || {};
		window.digitalData.utils.resetDataObject();
		window.digitalData.events = {"pageView": false, "siteInteraction": true};
		window.digitalData.interaction = {"name": interactionName};
		if(typeof _satellite!=="undefined")_satellite.track("track");
	}

	function replaceCommaWithHphen(nameVal){
		var str = nameVal.toString();
		return str!= undefined ? str.split(",").join("-").toLowerCase() : str.toLowerCase();
	}
	function replaceSpaceWithHphen(nameVal){
		var str = nameVal.toString();
		return str!= undefined ? str.split(" ").join("-").toLowerCase() : str.toLowerCase();
	}

    });
})(window);
/**
 * implementation to support button click analytics interaction track in modal
 * ref: https://jira.dcct.cibc.com:8443/browse/DDI-12648
 */
(function(window, document) {
    "use strict";

    $(document).on('cibcmodal:loaded',function() {
        function analyticsInteraction(context,interactionName) {
            updateDataLayer(interactionName);
            $(context)[0].click();
        }
        setTimeout(function () {
            $("a[data-ain]").each(function (idx, elm) {
                var interactionName = $(elm).attr("data-ain");
                $(elm).on('mousedown',function(e) {
                    if (e.button == 0) {
                        analyticsInteraction(this,interactionName);
                    }
                });
                $(elm).on('keydown', function(e) {
                    if (e.keyCode == 13) {
                        e.preventDefault();
                        analyticsInteraction(this,interactionName);
                    }
                });
            });
            
        }, 500);
    });

    function updateDataLayer(interactionName){
        window.digitalData = {};
        window.digitalData.events = {};
        window.digitalData.interaction = window.digitalData.interaction || {};
        window.digitalData.events.siteInteraction=true;
        window.digitalData.interaction.name=interactionName;
        if(typeof _satellite!=="undefined")_satellite.track("track");
    }
})(window, document);
(function () {
    $(".ratesandfeespattern .ratesandfees-inner hr").each(function(){
        var secText = $(this).closest('div').find(".column.sectitle");
        if($(secText).text().trim().length>0){
            $(this).removeClass('hide');
        }
        else{
            $(this).addClass('hide');
        }
    });
    $(".ratesandfeespattern .ratesandfees-inner .cardrow").each(function () {
        var secText = $(this).closest('div').find(".sec4childContentrow");
        if ($(secText).length > 0) {
            if ($(secText)[0].children[1].innerText.trim().length > 0) {
                const childElements = $(secText)[0].children;
                for (let i = 0; i < childElements.length; i++) {
                    childElements[i].classList.add('haveTwoContents');
                }
            }
        }
    });
})(window);
(function(window) {
    var ANDROID_CTA = $('.multi-cta .cta-appbanner.android-bnr-toggle');
    var APPLE_CTA = $('.multi-cta .cta-appbanner.apple-bnr-toggle');
    var userAgent = navigator.userAgent || navigator.vendor || window.opera;
    if (/android/i.test(userAgent)) {
        APPLE_CTA.each(function(){
            if($(this).siblings().length) {
                $(this).addClass('applebnr-hidden');
                if($(this).hasClass('stack')){
                    $(this).parent().removeClass('stack');
                }
            }
        });
        ANDROID_CTA.each(function(){
            if($(this).siblings().length) {
                $(this).removeClass('androidbnr-hidden');
            }
        });
    } else if ((/iPad|iPhone|iPod/.test(userAgent) && !window.MSStream) || (userAgent.includes('Macintosh') && 'ontouchend' in document)) {
        ANDROID_CTA.each(function(){
            if($(this).siblings().length) {
                $(this).addClass('androidbnr-hidden');
                if($(this).hasClass('stack')){
                    $(this).parent().removeClass('stack');
                }
            }
        });
        APPLE_CTA.each(function(){
            if($(this).siblings().length) {
                $(this).removeClass('applebnr-hidden');
            }
        });
    } else {
        APPLE_CTA.each(function(){
            $(this).removeClass('applebnr-hidden');
            if($(this).hasClass('stack')){
                $(this).parent().addClass('stack');
            }
        });
        ANDROID_CTA.each(function(){
            $(this).removeClass('androidbnr-hidden');
            if($(this).hasClass('stack')){
                $(this).parent().addClass('stack');
            }
        });
    }
})(window);
/**
 * AEM Digital Demo Component
 * Carousel/stepper component for desktop web browser demo screens.
 */
(function (window, document, $) {
    'use strict';

    var SELECTORS = {
        COMPONENT: '.aemdigitaldemo',
        CONTAINER: '.aemdigitaldemo__container',
        STEP_IMAGE: '.aemdigitaldemo__step-image',
        STEP_CONTENT: '.aemdigitaldemo__step-content',
        HOTSPOT: '.aemdigitaldemo__hotspot',
        SCREENSHOT: '.aemdigitaldemo__screenshot',
        NAV_PREV: '.aemdigitaldemo__nav-prev',
        NAV_NEXT: '.aemdigitaldemo__nav-next',
        NEXT_ARROW: '.aemdigitaldemo__nav-next-arrow',
        STARTOVER: '.aemdigitaldemo__nav-startover',
        PROGRESS_FILL: '.aemdigitaldemo__progress-fill',
        PROGRESS_BAR: '.aemdigitaldemo__progress-bar',
        CURRENT_STEP_NUM: '.aemdigitaldemo__current-step-num',
        TOTAL_STEPS_NUM: '.aemdigitaldemo__total-steps-num',
        STEP_LABEL: '.aemdigitaldemo__step-label',
        TAB: '.aemdigitaldemo__tab'
    };

    var CLASSES = {
        ACTIVE_IMAGE: 'aemdigitaldemo__step-image--active',
        ACTIVE_CONTENT: 'aemdigitaldemo__step-content--active',
        ACTIVE_TAB: 'aemdigitaldemo__tab--active',
        STARTOVER_MODE: 'aemdigitaldemo__nav-next--startover',
        COMPLETED_LABEL: 'aemdigitaldemo__step-label--completed'
    };

    var BUFFER_AHEAD = 3;          // Number of images to preload ahead of current step
    var HOTSPOT_RADIUS = 22;        // Must match half of hotspot width/height in CSS (44px / 2)
    var PAN_MARGIN = 10;            // Extra clearance beyond hotspot edge before panning
    var FIGMA_OFFSET = 40;          // Compensates for object-fit:cover cropping ~20px from artboard edges
    var MOBILEAPP_OFFSET = 40;      // Compensates for Figma phone mockup frame's 40px inner padding
    var PAN_TRANSITION_MS = 800;    // Fallback; overridden per-instance from CSS --aemdigitaldemo-pan-transition-ms

    // =========================================================================
    // Analytics — VRG implementation (DDI-37255)
    // =========================================================================

    /**
     * Map data-view attribute to analytics device token.
     * @param {string} view  'desktop' | 'webmobile' | 'mobileapp'
     * @returns {string} 'desktop' | 'tablet' | 'mobile'
     */
    function getViewDevice(view) {
        if (view === 'mobileapp') return 'mobile';
        if (view === 'webmobile') return 'tablet';
        return 'desktop';
    }

    /**
     * Fire step-load analytics event.
     * - interactiveToolStart on step 2
     * - interactiveToolComplete on last step
     * - siteInteraction on every step
     */
    function trackStepLoad(currentStep, totalSteps, device) {
        if (!window.digitalData || !window.digitalData.utils || !window.digitalData.site || !window.digitalData.page) return;
        var site = window.digitalData.site;
        var page = window.digitalData.page;
        var interactionName = site.brand + ':' + site.name + ':' + page.name + ':' + device + ':' + page.language + ':' + currentStep + '/' + totalSteps;

        window.digitalData.utils.resetDataObject();
        window.digitalData.events = { siteInteraction: true };
        window.digitalData.interaction = { name: interactionName };
        window.digitalData.interactiveTool = window.digitalData.interactiveTool || {};
        window.digitalData.interactiveTool.name = page.name;

        // interactiveToolStart fires only on step 2 load
        if (currentStep === 2) {
            window.digitalData.events.interactiveToolStart = true;
        }
        // interactiveToolComplete fires only on last step load
        if (currentStep === totalSteps) {
            window.digitalData.events.interactiveToolComplete = true;
        }

        if (typeof _satellite !== 'undefined') _satellite.track('track');
    }

    /**
     * Fire navigation click analytics event (forward/backward arrow).
     */
    function trackNavClick(direction, currentStep, totalSteps, device) {
        if (!window.digitalData || !window.digitalData.utils || !window.digitalData.site || !window.digitalData.page) return;
        var site = window.digitalData.site;
        var page = window.digitalData.page;
        var interactionName = site.brand + ':' + site.name + ':' + page.name + ':' + device + ':' + page.language + ':' + direction + ':' + currentStep + '/' + totalSteps;

        window.digitalData.utils.resetDataObject();
        window.digitalData.events = { siteInteraction: true };
        window.digitalData.interaction = { name: interactionName };
        window.digitalData.interactiveTool = window.digitalData.interactiveTool || {};
        window.digitalData.interactiveTool.name = page.name;

        if (typeof _satellite !== 'undefined') _satellite.track('track');
    }

    /**
     * Fire restart button analytics event.
     */
    function trackRestart(device) {
        if (!window.digitalData || !window.digitalData.utils || !window.digitalData.site || !window.digitalData.page) return;
        var site = window.digitalData.site;
        var page = window.digitalData.page;
        var interactionName = site.brand + ':' + site.name + ':' + page.name + ':' + device + ':' + page.language + ':restart';

        window.digitalData.utils.resetDataObject();
        window.digitalData.events = { siteInteraction: true };
        window.digitalData.interaction = { name: interactionName };
        window.digitalData.interactiveTool = window.digitalData.interactiveTool || {};
        window.digitalData.interactiveTool.name = page.name;

        if (typeof _satellite !== 'undefined') _satellite.track('track');
    }

    /**
     * Stepper instance for a single view container (desktop or mobileapp).
     */
    function DemoStepper($container, panTransitionMs) {
        this.$container = $container;
        this.panTransitionMs = panTransitionMs || PAN_TRANSITION_MS;
        this.view = $container.attr('data-view') || '';
        this.currentStep = 0;
        this.totalSteps = 0;
        this.skipPositioning = false;
        this.$stepImages = $container.find(SELECTORS.STEP_IMAGE);
        this.$stepContents = $container.find(SELECTORS.STEP_CONTENT);
        this.$prevBtn = $container.find(SELECTORS.NAV_PREV);
        this.$nextBtn = $container.find(SELECTORS.NAV_NEXT);
        this.$progressFill = $container.find(SELECTORS.PROGRESS_FILL);
        this.$progressBar = $container.find(SELECTORS.PROGRESS_BAR);
        this.$currentStepNum = $container.find(SELECTORS.CURRENT_STEP_NUM);
        this.$totalStepsNum = $container.find(SELECTORS.TOTAL_STEPS_NUM);
        this.nextBtnLabel = this.$nextBtn.attr('aria-label') || '';
        this.startOverLabel = this.$nextBtn.find(SELECTORS.STARTOVER).text().trim() || this.nextBtnLabel;

        this.init();
    }

    DemoStepper.prototype.init = function () {
        this.totalSteps = this.$stepImages.length;
        this.preloaded = false;
        if (this.totalSteps === 0) {
            return;
        }

        this.$totalStepsNum.text(this.totalSteps);
        this.$progressBar.attr('aria-valuemax', this.totalSteps);
        this.updateState();
        this.positionHotspots();
        this.bindEvents();
    };

    DemoStepper.prototype.startPreloading = function () {
        if (this.preloaded || this.totalSteps <= 1) {
            return;
        }
        this.preloaded = true;
        this.loadAhead(0);
    };

    DemoStepper.prototype.loadAhead = function (fromIndex) {
        for (var i = fromIndex; i <= Math.min(fromIndex + BUFFER_AHEAD, this.totalSteps - 1); i++) {
            this.loadImage(i);
        }
    };

    DemoStepper.prototype.loadImage = function (index) {
        var self = this;
        var $img = this.$stepImages.eq(index).find(SELECTORS.SCREENSHOT);
        var dataSrc = $img.attr('data-src');
        if (dataSrc && !$img.attr('src')) {
            $img.attr('src', dataSrc);
            $img.removeAttr('data-src');
            $img.on('load.aemdigitaldemo', function () {
                $(this).off('load.aemdigitaldemo');
                self.positionHotspotsForImage($(this));
            });
        }
    };

    DemoStepper.prototype.bindEvents = function () {
        var self = this;

        this.$prevBtn.on('click', function () {
            var targetStep = Math.max(0, self.currentStep - 1);
            trackNavClick('backward', targetStep + 1, self.totalSteps, getViewDevice(self.view));
            self.goToStep(targetStep);
        });

        this.$nextBtn.on('click', function () {
            if (self.currentStep === self.totalSteps - 1) {
                trackRestart(getViewDevice(self.view));
                self.goToStep(0);
            } else {
                var targetStep = self.currentStep + 1;
                trackNavClick('forward', targetStep + 1, self.totalSteps, getViewDevice(self.view));
                self.goToStep(targetStep);
            }
        });

        this.$container.find(SELECTORS.HOTSPOT).on('click', function () {
            if (self.currentStep < self.totalSteps - 1) {
                self.goToStep(self.currentStep + 1);
            }
        });

        // Position hotspots after images load
        this.$container.find(SELECTORS.SCREENSHOT).each(function () {
            var img = this;
            if (img.complete) {
                self.positionHotspotsForImage($(img));
            } else {
                $(img).on('load', function () {
                    self.positionHotspotsForImage($(this));
                });
            }
        });
    };

    DemoStepper.prototype.goToStep = function (index) {
        if (index < 0 || index >= this.totalSteps) {
            return;
        }
        this.currentStep = index;
        this.loadAhead(index);
        this.updateState();
        if (!this.skipPositioning) {
            this.positionHotspots();
        }
        // Analytics: track step load (1-based step number)
        trackStepLoad(index + 1, this.totalSteps, getViewDevice(this.view));
    };

    DemoStepper.prototype.reset = function () {
        this.goToStep(0);
    };

    DemoStepper.prototype.updateState = function () {
        var self = this;
        var isLastStep = this.currentStep === this.totalSteps - 1;
        var isFirstStep = this.currentStep === 0;
        var stepNumber = this.currentStep + 1;

        this.$stepImages.removeClass(CLASSES.ACTIVE_IMAGE);
        this.$stepImages.eq(this.currentStep).addClass(CLASSES.ACTIVE_IMAGE);

        this.$stepContents.removeClass(CLASSES.ACTIVE_CONTENT);
        this.$stepContents.eq(this.currentStep).addClass(CLASSES.ACTIVE_CONTENT);

        this.$stepContents.each(function (i) {
            var $label = $(this).find(SELECTORS.STEP_LABEL);
            var stepText = $label.attr('data-step-text');
            var completedText = $label.attr('data-completed-text');
            var num = $label.attr('data-step-number');

            if (i === self.totalSteps - 1 && isLastStep) {
                $label.text(completedText);
                $label.addClass(CLASSES.COMPLETED_LABEL);
            } else {
                $label.text(stepText + ' ' + num);
                $label.removeClass(CLASSES.COMPLETED_LABEL);
            }
        });

        var progressPercent = (stepNumber / this.totalSteps) * 100;
        this.$progressFill.css('width', progressPercent + '%');
        this.$currentStepNum.text(stepNumber);
        this.$progressBar.attr('aria-valuenow', stepNumber);

        this.$prevBtn.prop('disabled', isFirstStep);
        if (isFirstStep) {
            this.$prevBtn.hide();
        } else {
            this.$prevBtn.show();
        }

        if (isLastStep) {
            this.$nextBtn.addClass(CLASSES.STARTOVER_MODE);
            this.$nextBtn.find(SELECTORS.NEXT_ARROW).hide();
            this.$nextBtn.find(SELECTORS.STARTOVER).css('display', 'inline-flex');
            this.$nextBtn.attr('aria-label', this.startOverLabel);
        } else {
            this.$nextBtn.removeClass(CLASSES.STARTOVER_MODE);
            this.$nextBtn.find(SELECTORS.NEXT_ARROW).show();
            this.$nextBtn.find(SELECTORS.STARTOVER).css('display', '');
            this.$nextBtn.attr('aria-label', this.nextBtnLabel);
        }
    };

    DemoStepper.prototype.positionHotspots = function () {
        var self = this;
        this.$container.find(SELECTORS.HOTSPOT).each(function () {
            var $hotspot = $(this);
            var $img = $hotspot.siblings(SELECTORS.SCREENSHOT);
            self.positionHotspotsForImage($img);
        });
    };

    DemoStepper.prototype.positionHotspotsForImage = function ($img) {
        if (!$img.length) {
            return;
        }

        var img = $img[0];
        var naturalWidth = img.naturalWidth;
        var naturalHeight = img.naturalHeight;

        if (!naturalWidth || !naturalHeight) {
            return;
        }

        var $stepImage = $img.closest(SELECTORS.STEP_IMAGE);
        var $hotspot = $stepImage.find(SELECTORS.HOTSPOT);

        if (!$hotspot.length) {
            return;
        }

        var hotspotX = parseInt($hotspot.attr('data-hotspot-x'), 10);
        var hotspotY = parseInt($hotspot.attr('data-hotspot-y'), 10);

        if (isNaN(hotspotX) || isNaN(hotspotY)) {
            return;
        }

        var containerRect = $stepImage[0].getBoundingClientRect();
        var containerWidth = containerRect.width;
        var containerHeight = containerRect.height;

        // Element is hidden (display:none) — getBoundingClientRect returns 0; skip positioning
        if (!containerWidth || !containerHeight) {
            return;
        }

        var scaleX = containerWidth / naturalWidth;
        var scaleY = containerHeight / naturalHeight;

        // Detect if this is a contain-mode view (mobile app)
        var isMobileApp = $img.hasClass('aemdigitaldemo__screenshot--mobileapp');
        var isWebMobile = $img.hasClass('aemdigitaldemo__screenshot--webmobile');

        var pixelX, pixelY, scale, renderedWidth, cropOffsetX;
        var panOffsetDesktop = 0;
        var maCropping = false;
        var maPanOffset = 0;

        if (isMobileApp) {
            // Use actual img element position relative to step-image container
            var imgRect = $img[0].getBoundingClientRect();
            var stepImageRect = $stepImage[0].getBoundingClientRect();

            var imgOffsetX = imgRect.left - stepImageRect.left;
            var imgOffsetY = imgRect.top - stepImageRect.top;
            var imgWidth = imgRect.width;
            var imgHeight = imgRect.height;

            if (!imgWidth || !imgHeight) {
                return;
            }

            // Determine if object-fit:cover is cropping (fixed height on desktop)
            // On mobile (<639px), CSS sets height:auto so no cropping occurs
            var maScaleX = imgWidth / naturalWidth;
            var maScaleY = imgHeight / naturalHeight;
            var maCoverScale = Math.max(maScaleX, maScaleY);
            var maRenderedHeight = naturalHeight * maCoverScale;
            maCropping = (maRenderedHeight - imgHeight) > 1;

            if (maCropping) {
                // object-fit:cover with object-position:top center — use cover math + pan
                var maCropOffsetX = ((naturalWidth * maCoverScale) - imgWidth) / 2;

                pixelX = ((hotspotX + MOBILEAPP_OFFSET) * maCoverScale) - maCropOffsetX + imgOffsetX;
                pixelY = ((hotspotY + MOBILEAPP_OFFSET) * maCoverScale) + imgOffsetY;

                // Auto-pan if hotspot would be below visible image area
                maPanOffset = 0;
                var maVisibleBottom = imgHeight + imgOffsetY;
                if (pixelY + HOTSPOT_RADIUS + PAN_MARGIN > maVisibleBottom) {
                    maPanOffset = pixelY + HOTSPOT_RADIUS + PAN_MARGIN - maVisibleBottom;
                    var maMaxPan = maRenderedHeight - imgHeight;
                    if (maPanOffset > maMaxPan) {
                        maPanOffset = maMaxPan;
                    }
                    if (maPanOffset < 0) {
                        maPanOffset = 0;
                    }
                    pixelY = pixelY - maPanOffset;
                }
                $img.css('object-position', 'center ' + (-maPanOffset) + 'px');
            } else {
                // No cropping (mobile stacked, height:auto) — simple scale
                pixelX = ((hotspotX + MOBILEAPP_OFFSET) * maScaleX) + imgOffsetX;
                pixelY = ((hotspotY + MOBILEAPP_OFFSET) * maScaleY) + imgOffsetY;
            }
        } else if (isWebMobile) {
            // Use actual img element rect — on desktop the img is width:auto (narrower than container)
            // and flex-centered; on mobile it fills the container. Using the img rect handles both.
            var wbImgRect = $img[0].getBoundingClientRect();
            var wbStepRect = $stepImage[0].getBoundingClientRect();

            var wbImgOffsetX = wbImgRect.left - wbStepRect.left;
            var wbImgOffsetY = wbImgRect.top - wbStepRect.top;
            var wbImgWidth = wbImgRect.width;
            var wbImgHeight = wbImgRect.height;

            // object-fit: cover — uniform scale = max of both axes
            var wbScaleX = wbImgWidth / naturalWidth;
            var wbScaleY = wbImgHeight / naturalHeight;
            var wbScale = Math.max(wbScaleX, wbScaleY);

            // object-position: top center — horizontal crop centered, no top crop
            var wbCropOffsetX = ((naturalWidth * wbScale) - wbImgWidth) / 2;

            pixelX = ((hotspotX + FIGMA_OFFSET) * wbScale) - wbCropOffsetX + wbImgOffsetX;
            pixelY = ((hotspotY + FIGMA_OFFSET) * wbScale) + wbImgOffsetY;

            // Auto-pan if hotspot would be clipped below visible area
            var panOffset = 0;
            if (pixelY + HOTSPOT_RADIUS + PAN_MARGIN > containerHeight) {
                panOffset = pixelY + HOTSPOT_RADIUS + PAN_MARGIN - containerHeight;
                var maxPan = (naturalHeight * wbScale) - wbImgHeight;
                if (panOffset > maxPan) {
                    panOffset = maxPan;
                }
                if (panOffset < 0) {
                    panOffset = 0;
                }
                pixelY = pixelY - panOffset;
            }
            $img.css('object-position', 'center ' + (-panOffset) + 'px');
        } else {
            // object-fit: cover — image fills container, cropped
            scale = Math.max(scaleX, scaleY);
            renderedWidth = naturalWidth * scale;
            cropOffsetX = (renderedWidth - containerWidth) / 2;

            pixelX = ((hotspotX + FIGMA_OFFSET) * scale) - cropOffsetX;
            pixelY = (hotspotY + FIGMA_OFFSET) * scale;

            // Auto-pan if hotspot would be clipped below visible area
            panOffsetDesktop = 0;
            if (pixelY + HOTSPOT_RADIUS + PAN_MARGIN > containerHeight) {
                panOffsetDesktop = pixelY + HOTSPOT_RADIUS + PAN_MARGIN - containerHeight;
                var maxPanDesktop = (naturalHeight * scale) - containerHeight;
                if (panOffsetDesktop > maxPanDesktop) {
                    panOffsetDesktop = maxPanDesktop;
                }
                if (panOffsetDesktop < 0) {
                    panOffsetDesktop = 0;
                }
                pixelY = pixelY - panOffsetDesktop;
            }
            $img.css('object-position', 'center ' + (-panOffsetDesktop) + 'px');
        }

        $hotspot.css({
            left: pixelX + 'px',
            top: pixelY + 'px'
        });

        // Mobile app on mobile: scroll page so hotspot is visible if outside viewport
        if (isMobileApp && window.matchMedia && window.matchMedia('(max-width: 639px)').matches) {
            if ($stepImage.hasClass(CLASSES.ACTIVE_IMAGE)) {
                var hotspotDocOffset = $hotspot.offset();
                if (hotspotDocOffset) {
                    var viewportH = $(window).height();
                    var scrollT = $(window).scrollTop();
                    var hTop = hotspotDocOffset.top;
                    var hBottom = hTop + (HOTSPOT_RADIUS * 2);
                    if (hBottom + 10 > scrollT + viewportH || hTop - 10 < scrollT) {
                        var targetScroll = hTop - (viewportH / 2) + HOTSPOT_RADIUS;
                        if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
                            window.scrollTo(window.scrollX || 0, targetScroll);
                        } else {
                            $('html, body').animate({ scrollTop: targetScroll }, 300);
                        }
                    }
                }
            }
        }

        // If image is panning, delay showing hotspot until transition completes
        var panActive = false;
        if (isMobileApp && maCropping) {
            panActive = (Math.abs(maPanOffset) > 0);
        } else if (!isMobileApp && !isWebMobile) {
            panActive = (Math.abs(panOffsetDesktop) > 0);
        } else if (isWebMobile) {
            panActive = (Math.abs(panOffset) > 0);
        }

        if (panActive) {
            $hotspot.removeClass('aemdigitaldemo__hotspot--positioned');
            clearTimeout($hotspot.data('panTimer'));
            $hotspot.data('panTimer', setTimeout(function () {
                $hotspot.addClass('aemdigitaldemo__hotspot--positioned');
                $hotspot.removeData('panTimer');
            }, this.panTransitionMs)); // Synced from CSS --aemdigitaldemo-pan-transition-ms
        } else {
            clearTimeout($hotspot.data('panTimer'));
            $hotspot.removeData('panTimer');
            $hotspot.addClass('aemdigitaldemo__hotspot--positioned');
        }
    };

    /**
     * Main component controller - manages tabs and stepper instances.
     */
    function AemDigitalDemo($el) {
        this.$el = $el;
        this.steppers = {};
        this.activeView = null;

        // Read pan duration from CSS custom property so JS stays in sync automatically
        var panDurationStr = getComputedStyle($el[0]).getPropertyValue('--aemdigitaldemo-pan-transition-ms').trim();
        this.panTransitionMs = parseInt(panDurationStr, 10) || PAN_TRANSITION_MS;

        this.initSteppers();
        this.bindTabEvents();
        this.bindResizeEvent();
        this.checkDeepLink();
    }

    AemDigitalDemo.prototype.initSteppers = function () {
        var self = this;
        this.$el.find(SELECTORS.CONTAINER).each(function () {
            var $container = $(this);
            var view = $container.attr('data-view');
            if (view) {
                self.steppers[view] = new DemoStepper($container, self.panTransitionMs);
                if ($container.is(':visible')) {
                    self.activeView = view;
                }
            }
        });
        // Only preload images for visible tabs
        for (var view in this.steppers) {
            if (this.steppers.hasOwnProperty(view)) {
                var $container = this.steppers[view].$container;
                if ($container.is(':visible')) {
                    this.steppers[view].startPreloading();
                }
            }
        }
    };

    AemDigitalDemo.prototype.bindTabEvents = function () {
        var self = this;
        this.$el.find(SELECTORS.TAB).on('click', function () {
            var $tab = $(this);
            var targetView = $tab.attr('data-tab');

            // Update tab active states and roving tabindex
            self.$el.find(SELECTORS.TAB).removeClass(CLASSES.ACTIVE_TAB).attr('aria-selected', 'false').attr('tabindex', '-1');
            $tab.addClass(CLASSES.ACTIVE_TAB).attr('aria-selected', 'true').attr('tabindex', '0');

            // Show/hide containers
            self.$el.find(SELECTORS.CONTAINER).each(function () {
                var $container = $(this);
                var view = $container.attr('data-view');

                if (view === targetView) {
                    $container.show();
                } else if (view === 'webmobile' && targetView === 'desktop') {
                    // Let CSS media queries control webmobile visibility
                    $container.css('display', '');
                } else {
                    $container.hide();
                }
            });

            // Restore the saved step and reposition the target stepper (defer to allow reflow)
            self.activeView = targetView;
            if (self.steppers[targetView]) {
                self.steppers[targetView].startPreloading();
                self.steppers[targetView].skipPositioning = true;
                self.steppers[targetView].goToStep(self.steppers[targetView].currentStep);
                self.steppers[targetView].skipPositioning = false;
                // Double rAF ensures layout is fully resolved including flex children
                requestAnimationFrame(function () {
                    requestAnimationFrame(function () {
                        self.steppers[targetView].positionHotspots();
                        // Also reposition webmobile if it's visible
                        if (targetView === 'desktop' && self.steppers['webmobile']) {
                            self.steppers['webmobile'].positionHotspots();
                        }
                    });
                });
            }
        });

        // Arrow key navigation between tabs (WAI-ARIA tab pattern)
        this.$el.find(SELECTORS.TAB).on('keydown', function (e) {
            var $tabs = self.$el.find(SELECTORS.TAB);
            var index = $tabs.index(this);
            var newIndex = -1;

            if (e.keyCode === 37 || e.keyCode === 38) { // Left / Up
                newIndex = index > 0 ? index - 1 : $tabs.length - 1;
            } else if (e.keyCode === 39 || e.keyCode === 40) { // Right / Down
                newIndex = index < $tabs.length - 1 ? index + 1 : 0;
            }

            if (newIndex >= 0) {
                e.preventDefault();
                $tabs.eq(newIndex).focus().trigger('click');
            }
        });
    };

    AemDigitalDemo.prototype.bindResizeEvent = function () {
        var self = this;
        var resizeTimer;
        $(window).on('resize.aemdigitaldemo', function () {
            clearTimeout(resizeTimer);
            resizeTimer = setTimeout(function () {
                // Reposition all visible steppers (handles breakpoint switching)
                self.$el.find(SELECTORS.CONTAINER).each(function () {
                    var $container = $(this);
                    var view = $container.attr('data-view');
                    if (view && self.steppers[view] && $container.is(':visible')) {
                        self.steppers[view].positionHotspots();
                    }
                });
            }, 250);
        });
    };

    AemDigitalDemo.prototype.checkDeepLink = function () {
        var hash = window.location.hash ? window.location.hash.substring(1) : '';
        if (!hash) {
            return;
        }

        // Find the container whose ID matches the hash
        var self = this;
        var matched = false;
        this.$el.find(SELECTORS.CONTAINER).each(function () {
            var $container = $(this);
            if ($container.attr('id') === hash) {
                var view = $container.attr('data-view');
                if (view && view !== self.activeView) {
                    // Simulate tab click to switch to the matched view
                    self.$el.find(SELECTORS.TAB + '[data-tab="' + view + '"]').trigger('click');
                }
                matched = true;
                return false;
            }
        });

        // Also check if the component wrapper ID matches (scroll to it)
        if (!matched && this.$el.attr('id') === hash) {
            matched = true;
        }

        if (matched) {
            // Scroll to the component
            var offset = this.$el.offset();
            if (offset) {
                if (window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
                    window.scrollTo(window.scrollX || 0, offset.top - 20);
                } else {
                    $('html, body').animate({ scrollTop: offset.top - 20 }, 300);
                }
            }
        }
    };

    // Initialize all instances on page load
    $(function () {
        $(SELECTORS.COMPONENT).each(function () {
            new AemDigitalDemo($(this));
        });
    });

})(window, document, jQuery);

(function (context) {
    // ERROR MESSAGING
    var rabaForm = $('.raba-form');

    var patternValidate = context.patternValidate;

    var form = rabaForm.find('form');

    var action = form.attr('action');

    function getQuerystring(key, default_) {
        if (default_ == null)
            default_ = "";
        key = key.replace(/[\[]/, "\\\[").replace(/[\]]/, "\\\]");
        var regex = new RegExp("[\\?&]" + key + "=([^&#]*)");
        var qs = regex.exec(context.location.href);
        if (qs == null)
            return default_;
        else
            return qs[1];
    }

    function getDesc() {
        var formDesc = getQuerystring('raccc');
        if (formDesc.length > 0) {
            $('#contact-form #FormDescription', rabaForm).val(formDesc);
        }
    }

    function displayErrMsg(toDisplay) {
        $('#contact-form #' + toDisplay, rabaForm).show();
        rabaForm.data('isValid', false);
        // add red highlight on input field
        $('#contact-form #' + toDisplay, rabaForm).siblings('.formFieldSingleLine').addClass('errorRed').attr('aria-invalid', true).attr('aria-describedby', toDisplay);
        if (toDisplay == 'Field7-err1' && $('#contact-form #' + toDisplay, rabaForm).closest('fieldset')[0]) {
            $('#contact-form #' + toDisplay, rabaForm).closest('fieldset').find('.WealthCheckbox').first().attr('aria-invalid', true).attr('aria-describedby', toDisplay);
        }
    }

    function hideAllErrors() {
        $('#contact-form .error', rabaForm).hide();
        rabaForm.data('isValid', true);
        // remove red highlight on input field
        $('#contact-form .errorRed').removeClass('errorRed').removeAttr('aria-invalid');
    }

    function hideError(toHide) {
        $('#contact-form #' + toHide, rabaForm).hide();
    }

    function showFields() {
        $('#contact-form #postalCodeSet', rabaForm).css({
            display: 'block'
        });
    }

    function hideFields() {
        $('#contact-form #postalCodeSet', rabaForm).css({
            display: 'none'
        });
    }

    function submitForm() {
        var language = (window.location.href.indexOf('/fr/') > -1) ? "-fr" : "";
        var requestData = $(form).serializeObject();
        var confirmationPage = requestData.form.collectedData.confirmPage;

        $.ajax({
            url: action,
            async: true,
            cache: false,
            type: 'POST',
            dataType: 'json',
            data: JSON.stringify(requestData, null, ' '),
            headers: {
                'accept': 'application/vnd.api+json',
                'brand': 'cibc',
                'content-type': 'application/vnd.api+json'
            },
            success: function () {
                window.location = "https://www.cibc.com/ca/" + confirmationPage;
            },
            error: function () {
                window.location = "https://www.cibc.com/ca/apply/afp-error" + language + ".html";
            }
        });
    }

    $(function () {
        rabaForm.each(function (i, form) {
            var $clientRadios = $('#contact-form .Field9', form);
            var $clientTypeFieldset = $('#contact-form .CommercialClientTypeCheckbox', form).closest('fieldset');
            if ($clientRadios.length && $clientTypeFieldset.length) {
                $clientTypeFieldset.hide();
                $clientRadios.on('change', function () {
                    if ($('#contact-form #Field9Opt1', form).prop('checked')) {
                        $clientTypeFieldset.show();
                    } else {
                        $clientTypeFieldset.hide();
                        $clientTypeFieldset.find('.CommercialClientTypeCheckbox').prop('checked', false);
                        $('#contact-form #Field10', form).val('');
                    }
                });
            }
        });

        rabaForm.each(function (i, form) {

            $('#contact-form', form).on('submit', function (event) {
                //hide all error messages
                hideAllErrors();

                //Field10 validation
                /* if($('#contact-form #Field10', form).val() == '0'){
                 displayErrMsg('Field10-err1');				
                 }
                 */
                if ($('.cibc-raba', form).length) {
                    //CIBC RABA VALIDATION
                    //Field 1 validation
                    if ($('#contact-form #Field1', form).val() == '') {
                        displayErrMsg('Field1-err1');
                    } else if (!patternValidate($('#contact-form #Field1', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field1-err2');
                    }
                    //Field 2 validation
                    if ($('#contact-form #Field2', form).val() == '') {
                        displayErrMsg('Field2-err1');
                    } else if (!patternValidate($('#contact-form #Field2', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field2-err2');
                    }
                    //Check to see if field is enabled
                    if ($('#contact-form #emailField', form).length) {
                        //Field 11 validation
                        if ($('#contact-form #Field11', form).val() == '') {
                            displayErrMsg('Field11-err1')
                        }
                        if ($('#contact-form #Field11', form).val() != '' && !patternValidate($('#contact-form #Field11', form).val(), 'email')) {
                            displayErrMsg('Field11-err2');
                        }
                    }
                    if (!$('#contact-form #postalCodeSet', form).length || $('#contact-form #postalCodeSet', rabaForm).is(":visible")) {
                        //Field 8 validation
                        if ($('#contact-form #Field8', form).val() == '') {
                            displayErrMsg('Field8-err1');
                        } else if (!patternValidate($('#contact-form #Field8', form).val(), 'postalCode')) {
                            displayErrMsg('Field8-err2');
                        }
                    } else {
                        $('#contact-form #Field8', form).val('');
                    }

                    //Field3 validation
                    if ($('#contact-form #Field3', form).val() == '') {
                        displayErrMsg('Field3-err2');
                    } else if (!patternValidate($('#contact-form #Field3', form).val(), 'phoneNumberFull')) {
                        displayErrMsg('Field3-err1');
                    }

                    //Field4 validation
                    if ($('#contact-form #Field4', form).val() == 'Ext') {
                        $('#contact-form #Field4', form).val() == '';

                    } else if (!patternValidate($('#contact-form #Field4', form).val(), 'wholeNumber')) {
                        displayErrMsg('Field4-err1');
                        $('#contact-form #Field4', form).val() == '';
                    }

                    //Field5 validation
                    if ($('#contact-form #Field5', form).val() == 'Alternate Phone') {
                        $('#contact-form #Field5', form).val() == '';
                    } else if (!patternValidate($('#contact-form #Field5', form).val(), 'phoneNumberFull')) {
                        displayErrMsg('Field5-err1');
                    }


                    //Field6 validation
                    if ($('#contact-form #Field6', form).val() == 'Ext') {
                        $('#contact-form #Field6', form).val() == '';

                    } else if (!patternValidate($('#contact-form #Field6', form).val(), 'wholeNumber')) {
                        displayErrMsg('Field6-err1');
                        $('#contact-form #Field6', form).val() == '';
                    }

                    //Field7 validation
                    if ($('#contact-form #Field7 option:selected', form).val() == '0') {
                        displayErrMsg('Field7-err1');
                    }

                    getDesc();

                    if ($(form).data('isValid')) {
                        var CQ_Analytics = {
                            PageDataMgr: {
                                data: {
                                    cmlPrimaryAreaCode: $('#contact-form #Field8', form).val(),
                                    cmlBestTimetoCall: $('#contact-form #Field7', form).val()
                                }
                            }
                        }
                        if (action.indexOf('ebm-forms') >= 0) {
                            event.preventDefault();
                            submitForm();
                        }

                    } else {
                        event.preventDefault();
                        event.stopPropagation();
                        $('[aria-invalid]').first().focus();
                    }
                } else if ($('.commercial-raba', form).length) {
                    // COMMERCIAL RABA VALIDATION
                    if ($('#contact-form #Field1', form).val() === '') {
                        displayErrMsg('Field1-err1');
                    } else if (!patternValidate($('#contact-form #Field1', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field1-err2');
                    }

                    if ($('#contact-form #Field2', form).val() === '') {
                        displayErrMsg('Field2-err1');
                    } else if (!patternValidate($('#contact-form #Field2', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field2-err2');
                    }

                    if ($('#contact-form #Field3', form).val() !== '' && !patternValidate($('#contact-form #Field3', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field3-err1');
                    }

                    if ($('#contact-form #Field4', form).val() === '') {
                        displayErrMsg('Field4-err2');
                    } else if (!patternValidate($('#contact-form #Field4', form).val(), 'phoneNumberFull')) {
                        displayErrMsg('Field4-err1');
                    }

                    if ($('#contact-form #Field5', form).val() === '') {
                        displayErrMsg('Field5-err1');
                    } else if (!patternValidate($('#contact-form #Field5', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field5-err2');
                    }

                    if ($('#contact-form #Field6', form).val() === '') {
                        displayErrMsg('Field6-err1');
                    } else if (!patternValidate($('#contact-form #Field6', form).val(), 'postalCode')) {
                        displayErrMsg('Field6-err2');
                    }

                    if ($('#contact-form #Field7', form).val() !== '' && !patternValidate($('#contact-form #Field7', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field7-err1');
                    }

                    if ($('#contact-form #Field8', form).val() === '') {
                        displayErrMsg('Field8-err1');
                    } else if (!patternValidate($('#contact-form #Field8', form).val(), 'email')) {
                        displayErrMsg('Field8-err2');
                    }

                    if (!$('#contact-form .Field9:checked', form).length) {
                        displayErrMsg('Field9-err1');
                    }

                    var selectedClientTypes = "";
                    $('#contact-form .CommercialClientTypeCheckbox', form).each(function (index, value) {
                        if ($(value).prop('checked')) {
                            selectedClientTypes += $(value).val() + ", ";
                        }
                    });
                    selectedClientTypes = selectedClientTypes.substring(0, selectedClientTypes.length - 2);
                    $('#contact-form #Field10', form).val(selectedClientTypes);

                    if ($('#contact-form #Field11 option:selected', form).val() === '0') {
                        displayErrMsg('Field11-err1');
                    }

                    //Field12 character limit validation (500 char max)
                    var inquiryText = $('#contact-form #Field12', form).val();
                    if (inquiryText.length > 500) {
                        displayErrMsg('Field12-err1');
                    }

                    getDesc();
                    if (!$(form).data('isValid')) {
                        event.preventDefault();
                        event.stopPropagation();
                        $('[aria-invalid]').first().focus();
                    } else {
                        if (action.indexOf('ebm-forms') >= 0) {
                            event.preventDefault();
                            submitForm();
                        }
                    }
                } else {
                    // WEALTH RABA VALIDATION
                    //Field1 validation
                    if ($('#contact-form #Field1', form).val() == '') {
                        displayErrMsg('Field1-err1');
                    } else if (!patternValidate($('#contact-form #Field1', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field1-err2');
                    } else if (!patternValidate($('#contact-form #Field1', form).val(), 'alphanumeric')) {
                        displayErrMsg('Field1-err2');
                    }
                    //Field2 validation
                    if ($('#contact-form #Field2', form).val() == '') {
                        displayErrMsg('Field2-err1');
                    } else if (!patternValidate($('#contact-form #Field2', form).val(), 'alphabetic2')) {
                        displayErrMsg('Field2-err2');
                    } else if (!patternValidate($('#contact-form #Field2', form).val(), 'alphanumeric')) {
                        displayErrMsg('Field2-err2');
                    }
                    //Field3 validation	
                    if ($('#contact-form #Field3 option:selected', form).val() == '0') {
                        displayErrMsg('Field3-err1');
                    }
                    //Field4 validation
                    //Sets the value of the current client switch (Field4)
                    if ($('#contact-form #Field4Value', form).prop('checked')) {
                        $('#contact-form #Field4', form).val($('#contact-form #Field4Checked', form).text());
                    } else {
                        $('#contact-form #Field4', form).val($('#contact-form #Field4Unchecked', form).text());
                    }
                    //Field5 validation
                    if ($('#contact-form #Field5 option:selected', form).val() == '0') {
                        displayErrMsg('Field5-err1');
                    }

                    if (!$('#contact-form #postalCodeSet', form).length || $('#contact-form #postalCodeSet', rabaForm).is(":visible")) {
                        //Field6 validation
                        if ($('#contact-form #Field6', form).val() == '') {
                            displayErrMsg('Field6-err1');
                        } else if (!patternValidate($('#contact-form #Field6', form).val(), 'postalCode')) {
                            displayErrMsg('Field6-err2');
                        }
                    } else {
                        ($('#contact-form #Field6', form).val() == '');
                    }
                    //Set the value of selected checkboxes (for Field7 form submission)
                    var selectedCheckboxes = "";
                    $('#contact-form .WealthCheckbox', form).each(function (index, value) {
                        if ($(value).prop('checked')) {
                            selectedCheckboxes += $(value).val() + ", ";
                        }
                    });
                    //Remove comma from last checkbox value
                    selectedCheckboxes = selectedCheckboxes.substring(0, selectedCheckboxes.length - 2);
                    $('#contact-form #Field7', form).val(selectedCheckboxes);
                    //Field7 Validation
                    if ($('#contact-form #Field7', form).val() == '') displayErrMsg('Field7-err1');

                    //Method of contact validation
                    if (!$('#contact-form .Field8:checked', form).length) {
                        displayErrMsg('Field8-err1');
                    } else {
                        //Phone Validation
                        if ($('#contact-form #Field8Opt1:checked', form).length) {
                            if ($('#contact-form #Field9', form).val() == '') {
                                displayErrMsg('Field9-err1');
                            } else if (!patternValidate($('#contact-form #Field9', form).val(), 'phoneNumberFull')) {
                                displayErrMsg('Field9-err2');
                            }
                            //Best time to call validation
                            if ($('#contact-form #Field10 option:selected', form).val() == '0') {
                                displayErrMsg('Field10-err1');
                            }
                        }
                        //Email Validation 
                        if ($('#contact-form #Field8Opt2:checked', form).length) {
                            if ($('#contact-form #Field11', form).val() == '') {
                                displayErrMsg('Field11-err1');
                            } else if (!patternValidate($('#contact-form #Field11', form).val(), 'email')) {
                                displayErrMsg('Field11-err2');
                            }
                            //Confirm Email validation
                            if ($('#contact-form #ConfirmEmail', form).val() == "") {
                                displayErrMsg('ConfirmEmail-err1');
                            } else if ($('#contact-form #Field11', form).val() != $('#contact-form #ConfirmEmail', form).val()) {
                                displayErrMsg('ConfirmEmail-err2');
                            }
                        }
                        // If both forms of contact are given, validate both
                        if ($('#contact-form #Field8Opt1:checked', form).length && $('#contact-form #Field11', form).val() != '' || $('#contact-form #Field8Opt2:checked', form).length && $('#contact-form #Field9', form).val() != '') {

                            //Phone validation
                            if (!patternValidate($('#contact-form #Field9', form).val(), 'phoneNumberFull')) {
                                displayErrMsg('Field9-err2');
                            }

                            //Best time to call validation
                            if ($('#contact-form #Field10 option:selected', form).val() == '0') {
                                displayErrMsg('Field10-err1');
                            }

                            //Email Validation
                            if (!patternValidate($('#contact-form #Field11', form).val(), 'email')) {
                                displayErrMsg('Field11-err2');
                            }

                            //Confirm Email validation
                            if ($('#contact-form #ConfirmEmail', form).val() == "") {
                                displayErrMsg('ConfirmEmail-err1');
                            } else if ($('#contact-form #Field11', form).val() != $('#contact-form #ConfirmEmail', form).val()) {
                                displayErrMsg('ConfirmEmail-err2');
                            }
                        }
                    }
                    //Opt-In Checkbox
                    if (!$('#contact-form #OptInCheckbox', form).prop('checked')) {
                        displayErrMsg('OptInCheckbox-err1');
                    }

                    getDesc();
                    if (!$(form).data('isValid')) {
                        event.preventDefault();
                        event.stopPropagation();
                        $('[aria-invalid]').first().focus();
                    } else {
                        if (action.indexOf('ebm-forms') >= 0) {
                            event.preventDefault();
                            submitForm();
                        }
                    }
                }
            });
        });
    });
})(window);
