var validationPatterns = new Array();
validationPatterns['dangerousChars'] = />|<|\&|#|\\|\[|\]|}|{|%|www\.|http:|https:|ftp|javascript|function|return|\&lt;|\&amp;|\&gt;|\&quot;$/gi; 
